package se.medbo.examplatform.ai.editorial;

import com.fasterxml.jackson.databind.ObjectMapper;
import java.sql.Types;
import java.time.OffsetDateTime;
import java.time.ZoneOffset;
import java.util.*;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpStatus;
import org.springframework.jdbc.core.simple.JdbcClient;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import se.medbo.examplatform.ai.generation.AiApiException;
import se.medbo.examplatform.ai.provider.AiProviderException;

@Service
public class EditorialJobService {
  private final JdbcClient jdbc; private final ObjectMapper mapper; private final AiEditorialProviderClient provider;
  private final EditorialPromptTemplateRegistry prompts; private final boolean enabled; private final int maxRetries,hourlyLimit;
  public EditorialJobService(JdbcClient jdbc,ObjectMapper mapper,AiEditorialProviderClient provider,EditorialPromptTemplateRegistry prompts,
      @Value("${ai.editorial.enabled:false}")boolean enabled,@Value("${ai.editorial.max-retries:2}")int maxRetries,
      @Value("${ai.editorial.request-limit-per-hour:30}")int hourlyLimit){this.jdbc=jdbc;this.mapper=mapper;this.provider=provider;this.prompts=prompts;this.enabled=enabled;this.maxRetries=maxRetries;this.hourlyLimit=hourlyLimit;}

  @Transactional public Map<String,Object> create(AiEditorialProviderClient.Request request,String actor,String key,String providerName,String model){
    if(!enabled)throw error(HttpStatus.SERVICE_UNAVAILABLE,"AI_FEATURE_DISABLED","AI-assisted generation is disabled");
    if(request.targets()==null||request.targets().size()!=1)throw error(HttpStatus.UNPROCESSABLE_ENTITY,"AI_EDITORIAL_TARGET_REQUIRED","Exactly one target fact is required");
    var inputQuality=EditorialInputSafety.classify(request.targets().getFirst().text());
    if(inputQuality==EditorialInputSafety.Quality.INVALID)throw error(HttpStatus.UNPROCESSABLE_ENTITY,"AI_EDITORIAL_INPUT_INVALID","The target does not contain meaningful factual content");
    boolean wordingOnly=request.operation()==EditorialOperationType.DETECT_AMBIGUITY;
    if(!wordingOnly&&(request.sources()==null||request.sources().isEmpty()))throw error(HttpStatus.UNPROCESSABLE_ENTITY,"AI_EDITORIAL_SOURCE_CONTENT_UNAVAILABLE","Stored linked Source content is required");
    if(Set.of(EditorialOperationType.REWRITE_FOR_CLARITY,EditorialOperationType.SIMPLIFY_LANGUAGE).contains(request.operation())
        && request.sources().stream().noneMatch(source->EditorialGrounding.plausiblySupports(request.targets().getFirst().text(),source.text())))
      throw error(HttpStatus.UNPROCESSABLE_ENTITY,"AI_EDITORIAL_INSUFFICIENT_EVIDENCE","Linked Sources do not plausibly support the target fact");
    int maximum=Set.of(EditorialOperationType.MAKE_ATOMIC,EditorialOperationType.SPLIT_FACT).contains(request.operation())?5:3;
    if(request.count()<1||request.count()>maximum)throw error(HttpStatus.UNPROCESSABLE_ENTITY,"AI_INVALID_GENERATION_REQUEST","Requested output count is outside the operation limit");
    long recent=jdbc.sql("SELECT count(*) FROM ai_generation_job WHERE requested_by=:actor AND created_at>now()-interval '1 hour'").param("actor",actor).query(Long.class).single();
    if(recent>=hourlyLimit)throw error(HttpStatus.TOO_MANY_REQUESTS,"AI_RATE_LIMIT_EXCEEDED","The hourly AI generation limit was reached");
    var existing=jdbc.sql("SELECT id FROM ai_generation_job WHERE requested_by=:actor AND idempotency_key=:key").param("actor",actor).param("key",key).query(UUID.class).list();
    if(!existing.isEmpty())return get(existing.getFirst());
    var target=request.targets().getFirst();var source=request.sources()==null||request.sources().isEmpty()?null:request.sources().getFirst();var id=UUID.randomUUID();var now=now();
    jdbc.sql("INSERT INTO ai_generation_job(id,job_type,operation_type,source_id,source_title,source_content,source_content_checksum,learning_objective_id,learning_objective_title,requested_by,requested_count,language,editorial_instruction,idempotency_key,status,provider,model,prompt_version,created_at,next_attempt_at,input_character_count,target_context,target_content_checksum) VALUES(:id,'EDITORIAL',:operation,:source,'Editorial source',:content,:sourceChecksum,:objective,:objectiveTitle,:actor,:count,:language,:instruction,:key,'QUEUED',:provider,:model,:prompt,:now,:now,:characters,CAST(:context AS jsonb),:targetChecksum)")
      .param("id",id).param("operation",request.operation().name()).param("source",source==null?null:source.sourceId(),Types.OTHER).param("content",source==null?null:source.text(),Types.VARCHAR).param("sourceChecksum",source==null?null:source.checksum(),Types.VARCHAR).param("objective",request.learningObjectiveId()).param("objectiveTitle",request.objectiveTitle()).param("actor",actor).param("count",request.count()).param("language",request.language()).param("instruction",blank(request.instruction()),Types.VARCHAR).param("key",key).param("provider",providerName).param("model",model).param("prompt",prompts.version(request.operation())).param("now",now).param("characters",request.sources()==null?target.text().length():request.sources().stream().mapToInt(s->s.text().length()).sum()).param("context",json(request)).param("targetChecksum",target.checksum()).update();
    jdbc.sql("INSERT INTO ai_editorial_target VALUES(:job,:fact,:factVersion,:version,:text,:checksum,0)").param("job",id).param("fact",target.factId()).param("factVersion",target.factVersionId()).param("version",target.version()).param("text",target.text()).param("checksum",target.checksum()).update();
    return get(id);
  }

  public Map<String,Object> get(UUID id){var rows=jdbc.sql("SELECT id,operation_type AS \"operationType\",result_type AS \"resultType\",learning_objective_id AS \"learningObjectiveId\",learning_objective_title AS \"learningObjectiveTitle\",requested_by AS \"requestedBy\",requested_count AS \"requestedCount\",status,provider,model,prompt_version AS \"promptVersion\",created_at AS \"createdAt\",started_at AS \"startedAt\",completed_at AS \"completedAt\",failed_at AS \"failedAt\",cancelled_at AS \"cancelledAt\",retry_count AS \"retryCount\",input_tokens AS \"inputTokens\",output_tokens AS \"outputTokens\",total_tokens AS \"totalTokens\",provider_request_id AS \"providerRequestId\",error_code AS \"errorCode\",error_message AS \"errorMessage\",version,(SELECT count(*) FROM ai_editorial_proposal p WHERE p.generation_job_id=ai_generation_job.id) AS \"resultCount\",(SELECT count(*) FROM ai_editorial_finding f WHERE f.generation_job_id=ai_generation_job.id) AS \"findingCount\" FROM ai_generation_job WHERE id=:id AND operation_type IS NOT NULL").param("id",id).query().listOfRows();if(rows.isEmpty())throw error(HttpStatus.NOT_FOUND,"AI_JOB_NOT_FOUND","Editorial job was not found");return rows.getFirst();}
  public List<Map<String,Object>> proposals(UUID job){get(job);var rows=jdbc.sql("SELECT id,generation_job_id AS \"generationJobId\",operation_type AS \"operationType\",target_fact_id AS \"targetFactId\",original_text AS \"originalText\",proposed_text AS \"proposedText\",edited_text AS \"editedText\",rationale,source_evidence::text AS \"sourceEvidence\",warnings::text AS warnings,coverage::text AS coverage,proposal_metadata::text AS \"proposalMetadata\",proposal_order AS \"proposalOrder\",confidence,status,resulting_fact_id AS \"resultingFactId\",resulting_fact_version_id AS \"resultingFactVersionId\",edit_count AS \"editCount\",created_at AS \"createdAt\",updated_at AS \"updatedAt\",version FROM ai_editorial_proposal WHERE generation_job_id=:id ORDER BY proposal_order NULLS LAST,created_at,id").param("id",job).query().listOfRows();rows.forEach(r->{parse(r,"sourceEvidence");parse(r,"warnings");parse(r,"coverage");parse(r,"proposalMetadata");});return rows;}
  public List<Map<String,Object>> findings(UUID job){get(job);var rows=jdbc.sql("SELECT id,generation_job_id AS \"generationJobId\",operation_type AS \"operationType\",target_fact_id AS \"targetFactId\",target_fact_version_id AS \"targetFactVersionId\",finding_type AS \"findingType\",severity,title,message,affected_text AS \"affectedText\",source_evidence::text AS \"sourceEvidence\",confidence,suggested_action AS \"suggestedAction\",finding_metadata::text AS metadata,status,dismissed_at AS \"dismissedAt\",dismissed_by AS \"dismissedBy\",dismissal_reason AS \"dismissalReason\",created_at AS \"createdAt\",version FROM ai_editorial_finding WHERE generation_job_id=:id ORDER BY created_at,id").param("id",job).query().listOfRows();rows.forEach(r->{parse(r,"sourceEvidence");parse(r,"metadata");});return rows;}
  public Map<String,Object> finding(UUID id){var rows=jdbc.sql("SELECT f.id,f.generation_job_id AS \"generationJobId\",f.operation_type AS \"operationType\",f.target_fact_id AS \"targetFactId\",f.target_fact_version_id AS \"targetFactVersionId\",f.finding_type AS \"findingType\",f.severity,f.title,f.message,f.affected_text AS \"affectedText\",f.source_evidence::text AS \"sourceEvidence\",f.confidence,f.suggested_action AS \"suggestedAction\",f.finding_metadata::text AS metadata,f.status,f.dismissed_at AS \"dismissedAt\",f.dismissed_by AS \"dismissedBy\",f.dismissal_reason AS \"dismissalReason\",f.created_at AS \"createdAt\",f.version,j.requested_by AS \"requestedBy\" FROM ai_editorial_finding f JOIN ai_generation_job j ON j.id=f.generation_job_id WHERE f.id=:id").param("id",id).query().listOfRows();if(rows.isEmpty())throw error(HttpStatus.NOT_FOUND,"AI_EDITORIAL_FINDING_NOT_FOUND","Editorial finding was not found");var row=rows.getFirst();parse(row,"sourceEvidence");parse(row,"metadata");return row;}
  @Transactional public Map<String,Object> dismissFinding(UUID id,String actor,String reason,long version){var current=finding(id);if("DISMISSED".equals(current.get("status")))return current;int changed=jdbc.sql("UPDATE ai_editorial_finding SET status='DISMISSED',dismissed_at=:now,dismissed_by=:actor,dismissal_reason=:reason,version=version+1 WHERE id=:id AND version=:version AND status='OPEN'").param("now",now()).param("actor",actor).param("reason",blank(reason),Types.VARCHAR).param("id",id).param("version",version).update();if(changed==0)throw error(HttpStatus.CONFLICT,"AI_EDITORIAL_FINDING_ALREADY_DISMISSED","The finding changed or was already dismissed");return finding(id);}
  public Map<String,Object> proposal(UUID id){var rows=jdbc.sql("SELECT p.*,p.source_evidence::text AS evidence_json,p.warnings::text AS warnings_json,j.requested_by,j.provider,j.model,j.prompt_version,j.created_at AS generated_at,j.provider_request_id,j.input_tokens,j.output_tokens,j.target_context::text AS target_context,t.target_fact_version_id,t.target_version,t.content_checksum AS original_checksum FROM ai_editorial_proposal p JOIN ai_generation_job j ON j.id=p.generation_job_id JOIN ai_editorial_target t ON t.generation_job_id=j.id AND t.target_fact_id=p.target_fact_id WHERE p.id=:id").param("id",id).query().listOfRows();if(rows.isEmpty())throw error(HttpStatus.NOT_FOUND,"AI_PROPOSAL_NOT_FOUND","Editorial proposal was not found");return rows.getFirst();}
  @Transactional public Map<String,Object> edit(UUID id,String text,long version){if(text==null||text.isBlank()||text.length()>500||text.contains("<"))throw error(HttpStatus.UNPROCESSABLE_ENTITY,"AI_EDITORIAL_OUTPUT_INVALID","Proposal text is invalid");int changed=jdbc.sql("UPDATE ai_editorial_proposal SET edited_text=:text,status='EDITED',edit_count=edit_count+1,updated_at=:now,version=version+1,normalized_text=:normalized WHERE id=:id AND version=:version AND status IN ('PROPOSED','EDITED')").param("text",text.trim()).param("now",now()).param("normalized",normalize(text)).param("id",id).param("version",version).update();if(changed==0)throw error(HttpStatus.CONFLICT,"AI_EDITORIAL_PROPOSAL_STALE","Proposal changed or is no longer editable");return proposal(id);}
  @Transactional public Map<String,Object> reject(UUID id,String reason,long version){int changed=jdbc.sql("UPDATE ai_editorial_proposal SET status='REJECTED',rejection_reason=:reason,updated_at=:now,version=version+1 WHERE id=:id AND version=:version AND status IN ('PROPOSED','EDITED')").param("reason",blank(reason),Types.VARCHAR).param("now",now()).param("id",id).param("version",version).update();if(changed==0)throw error(HttpStatus.CONFLICT,"AI_EDITORIAL_PROPOSAL_ALREADY_REJECTED","Proposal was already processed");return proposal(id);}
  @Transactional public Map<String,Object> cancel(UUID id){var job=get(id);if(!List.of("QUEUED","RUNNING").contains(job.get("status")))throw error(HttpStatus.CONFLICT,"AI_JOB_NOT_CANCELLABLE","Job cannot be cancelled");jdbc.sql("UPDATE ai_generation_job SET cancellation_requested=true,status=CASE WHEN status='QUEUED' THEN 'CANCELLED' ELSE status END,cancelled_at=CASE WHEN status='QUEUED' THEN :now ELSE cancelled_at END,version=version+1 WHERE id=:id").param("now",now()).param("id",id).update();return get(id);}
  @Transactional public void markAccepted(UUID id,UUID fact,UUID factVersion,String actor,long version){int changed=jdbc.sql("UPDATE ai_editorial_proposal SET status='ACCEPTED',resulting_fact_id=:fact,resulting_fact_version_id=:factVersion,accepted_by=:actor,accepted_at=:now,updated_at=:now,version=version+1 WHERE id=:id AND version=:version AND status IN ('PROPOSED','EDITED')").param("fact",fact).param("factVersion",factVersion).param("actor",actor).param("now",now()).param("id",id).param("version",version).update();if(changed==0)throw error(HttpStatus.CONFLICT,"AI_EDITORIAL_PROPOSAL_ALREADY_ACCEPTED","Proposal was already processed");var row=jdbc.sql("SELECT j.operation_type,j.prompt_version FROM ai_editorial_proposal p JOIN ai_generation_job j ON j.id=p.generation_job_id WHERE p.id=:id").param("id",id).query().singleRow();metric(row,"ACCEPTED_PROPOSAL");}

  public boolean workOne(){if(!enabled)return false;var ids=jdbc.sql("SELECT id FROM ai_generation_job WHERE job_type='EDITORIAL' AND status='QUEUED' AND cancellation_requested=false AND next_attempt_at<=now() ORDER BY created_at LIMIT 1").query(UUID.class).list();if(ids.isEmpty())return false;run(ids.getFirst());return true;}
  void run(UUID id){int claimed=jdbc.sql("UPDATE ai_generation_job SET status='RUNNING',started_at=coalesce(started_at,:now),version=version+1 WHERE id=:id AND status='QUEUED' AND cancellation_requested=false").param("now",now()).param("id",id).update();if(claimed==0)return;var row=jdbc.sql("SELECT * FROM ai_generation_job WHERE id=:id").param("id",id).query().singleRow();try{var request=mapper.readValue(String.valueOf(row.get("target_context")),AiEditorialProviderClient.Request.class).execution(id,(String)row.get("requested_by"),(Integer)row.get("retry_count"));var result=validate(request,provider.execute(request));if(Boolean.TRUE.equals(jdbc.sql("SELECT cancellation_requested FROM ai_generation_job WHERE id=:id").param("id",id).query(Boolean.class).single())){jdbc.sql("UPDATE ai_generation_job SET status='CANCELLED',cancelled_at=:now WHERE id=:id").param("now",now()).param("id",id).update();return;}persist(id,result);}catch(AiProviderException e){metric(row,"REJECTED_"+e.code());fail(id,(Integer)row.get("retry_count"),e);}catch(Exception e){metric(row,"REJECTED_INVALID_OUTPUT");fail(id,(Integer)row.get("retry_count"),new AiProviderException("AI_EDITORIAL_OUTPUT_INVALID",false,"Editorial output was invalid"));}}
  private AiEditorialProviderClient.Result validate(AiEditorialProviderClient.Request request,AiEditorialProviderClient.Result result){
    if(result==null||result.revisions()==null||result.findings()==null)invalid("Structured editorial output is required");
    if(EditorialInputSafety.classify(request.targets().getFirst().text())==EditorialInputSafety.Quality.SUSPICIOUS
        && result.findings().stream().allMatch(finding -> "KEEP_AS_IS".equals(finding.suggestedAction())
            || finding.type().startsWith("NO_") || "ALREADY_CLEAR".equals(finding.type())))
      throw new AiProviderException("AI_EDITORIAL_RESULT_INCONSISTENT_WITH_INPUT_VALIDATION",false,
          "The provider returned a positive result without addressing deterministic input-quality concerns");
    if(Set.of(EditorialOperationType.REWRITE_FOR_CLARITY,EditorialOperationType.SIMPLIFY_LANGUAGE).contains(request.operation())&&!result.revisions().isEmpty()){
      var meaningful=result.revisions().stream().filter(revision->!EditorialGrounding.noMeaningfulChange(request.targets().getFirst().text(),revision.proposedText())).toList();
      if(meaningful.isEmpty()){
        metric(request,"NO_OP_DISCARDED");
        var evidence=result.revisions().getFirst().evidence();
        result=new AiEditorialProviderClient.Result(List.of(),List.of(new AiEditorialProviderClient.Finding(
            "ALREADY_CLEAR","INFO",request.targets().getFirst().factId(),"Already clear",
            "The current wording could not be improved without changing its meaning.",null,evidence,"HIGH","KEEP_AS_IS",
            Map.of("resultType","ALREADY_CLEAR","discardedProposalCount",result.revisions().size()))),result.warnings(),result.usage());
      }else if(meaningful.size()!=result.revisions().size()){
        metric(request,"NO_OP_DISCARDED");
        result=new AiEditorialProviderClient.Result(meaningful,result.findings(),result.warnings(),result.usage());
      }
    }
    int revisions=result.revisions().size(),findings=result.findings().size();
    switch(request.operation()){
      case REWRITE_FOR_CLARITY,SIMPLIFY_LANGUAGE->{if(!((revisions>=1&&revisions<=3&&findings==0)||(revisions==0&&findings==1&&"ALREADY_CLEAR".equals(result.findings().getFirst().type()))))invalid("Rewrite output requires proposals or an already-clear result");}
      case SPLIT_FACT->{if(revisions<2||revisions>5||findings!=0)throw new AiProviderException("AI_EDITORIAL_SPLIT_REQUIRES_MULTIPLE_PROPOSALS",false,"Split output requires two to five proposals");}
      case MAKE_ATOMIC->{if(!((revisions>=2&&revisions<=5&&findings==0)||(revisions==0&&findings==1)))invalid("Atomicity output must be one finding or two to five proposals");}
      case CHECK_SOURCE_SUPPORT,EDITORIAL_REVIEW_NOTES->{if(revisions!=0||findings<1)invalid("Analysis operation requires findings only");}
      case DETECT_AMBIGUITY->{if(revisions!=0)invalid("Ambiguity analysis cannot produce revision proposals");}
    }
    var texts=new HashSet<String>();
    for(var revision:result.revisions()){
      if(revision.targetFactId()==null||request.targets().stream().noneMatch(t->t.factId().equals(revision.targetFactId()))||invalidText(revision.proposedText())||genericRationale(revision.rationale())||!texts.add(normalize(revision.proposedText())))invalid("Revision proposal validation failed");
      validateEvidence(request,revision.evidence(),true);
      if(revision.evidence().stream().noneMatch(evidence->EditorialGrounding.plausiblySupports(revision.proposedText(),evidence.quote())))throw new AiProviderException("AI_EDITORIAL_EVIDENCE_NOT_RELEVANT",false,"Proposal evidence is not relevant to the proposed claim");
      if(Set.of(EditorialOperationType.MAKE_ATOMIC,EditorialOperationType.SPLIT_FACT).contains(request.operation())&&!supportedByAnySource(request,revision.proposedText()))throw new AiProviderException("AI_EDITORIAL_INSUFFICIENT_EVIDENCE",false,"A split proposal is not present in the supplied Source context");
    }
    var allowedSeverities=Set.of("INFO","WARNING","HIGH","BLOCKING");
    var allowedAmbiguity=Set.of("NO_AMBIGUITY_FOUND","VAGUE_PRONOUN","MISSING_SUBJECT","UNCLEAR_TIME_SCOPE","UNCLEAR_GEOGRAPHIC_SCOPE","UNCLEAR_LEGAL_SCOPE","OVERLY_ABSOLUTE_WORDING","BROAD_GENERALISATION","MULTIPLE_INTERPRETATIONS","UNDEFINED_TERM","UNSTABLE_CURRENT_STATE_CLAIM","COMPOUND_CLAIM","UNCLEAR_ACTOR","UNCLEAR_RESPONSIBILITY");
    var allowedSupport=Set.of("FULL_SUPPORT_CONFIRMED","CLAIM_PARTIALLY_SUPPORTED","CLAIM_NOT_FOUND_IN_SOURCE","QUALIFIER_MISSING","SOURCE_SCOPE_MISMATCH","SOURCE_CONTENT_MISSING","SOURCE_CHANGED_SINCE_FACT_CREATION","EVIDENCE_AMBIGUOUS");
    for(var finding:result.findings()){
      if(finding.targetFactId()==null||request.targets().stream().noneMatch(t->t.factId().equals(finding.targetFactId()))||finding.type()==null||finding.type().isBlank()||!allowedSeverities.contains(finding.severity())||invalidText(finding.title())||invalidText(finding.message()))invalid("Editorial finding validation failed");
      if(request.operation()==EditorialOperationType.DETECT_AMBIGUITY&&!allowedAmbiguity.contains(finding.type()))invalid("Invalid ambiguity finding type");
      if(request.operation()==EditorialOperationType.CHECK_SOURCE_SUPPORT&&!allowedSupport.contains(finding.type()))invalid("Invalid Source-support finding type");
      if(request.operation()==EditorialOperationType.EDITORIAL_REVIEW_NOTES&&Set.of("APPROVE","REJECT","PUBLISH").contains(finding.suggestedAction()))invalid("Editorial notes cannot make lifecycle decisions");
      validateEvidence(request,finding.evidence(),request.operation()!=EditorialOperationType.DETECT_AMBIGUITY);
      if(request.operation()!=EditorialOperationType.CHECK_SOURCE_SUPPORT&&finding.evidence()!=null&&!finding.evidence().isEmpty()
          && finding.evidence().stream().noneMatch(evidence->EditorialGrounding.plausiblySupports(request.targets().getFirst().text(),evidence.quote())))
        throw new AiProviderException("AI_EDITORIAL_EVIDENCE_NOT_RELEVANT",false,"Finding evidence is not relevant to the target fact");
    }
    if(revisions==0&&findings==0&&request.operation()!=EditorialOperationType.DETECT_AMBIGUITY)invalid("Editorial output was empty");
    return result;
  }
  private void validateEvidence(AiEditorialProviderClient.Request request,List<AiEditorialProviderClient.Evidence> evidence,boolean required){if((evidence==null||evidence.isEmpty())&&required)throw new AiProviderException("AI_EDITORIAL_INSUFFICIENT_EVIDENCE",false,"Source evidence is required");if(evidence==null)return;for(var item:evidence){if(item.sourceId()==null)throw new AiProviderException("AI_EDITORIAL_EVIDENCE_SOURCE_MISMATCH",false,"Evidence Source ID is required");var source=request.sources().stream().filter(s->s.sourceId().equals(item.sourceId())).findFirst().orElseThrow(()->new AiProviderException("AI_EDITORIAL_EVIDENCE_SOURCE_MISMATCH",false,"Evidence Source was not supplied for this job"));if(item.quote()==null||item.quote().isBlank()||!source.text().contains(item.quote()))throw new AiProviderException("AI_EDITORIAL_EVIDENCE_NOT_IN_SOURCE",false,"Evidence was not found verbatim in its identified Source");}}
  private boolean supportedByAnySource(AiEditorialProviderClient.Request request,String text){String candidate=normalize(text).replaceAll("[.]$","");return request.sources().stream().map(AiEditorialProviderClient.Source::text).map(this::normalize).anyMatch(source->source.contains(candidate));}
  private boolean invalidText(String text){return text==null||text.isBlank()||text.length()>2000||text.contains("<")||text.toLowerCase(Locale.ROOT).contains("<script");}
  private void invalid(String message){throw new AiProviderException("AI_EDITORIAL_OUTPUT_INVALID",false,message);}
  @Transactional void persist(UUID job,AiEditorialProviderClient.Result result){var now=now();int order=0;for(var p:result.revisions())jdbc.sql("INSERT INTO ai_editorial_proposal(id,generation_job_id,operation_type,target_fact_id,original_text,proposed_text,edited_text,rationale,source_evidence,warnings,coverage,confidence,status,created_at,updated_at,normalized_text,proposal_order,proposal_metadata) SELECT :id,:job,j.operation_type,:target,t.original_text,:text,:text,:rationale,CAST(:evidence AS jsonb),CAST(:warnings AS jsonb),CAST(:coverage AS jsonb),:confidence,'PROPOSED',:now,:now,:normalized,:proposalOrder,CAST(:metadata AS jsonb) FROM ai_generation_job j JOIN ai_editorial_target t ON t.generation_job_id=j.id WHERE j.id=:job ON CONFLICT DO NOTHING").param("id",UUID.randomUUID()).param("job",job).param("target",p.targetFactId()).param("text",p.proposedText().trim()).param("rationale",p.rationale()).param("evidence",json(p.evidence())).param("warnings",json(p.warnings())).param("coverage",json(p.coverage())).param("confidence",p.confidence(),Types.VARCHAR).param("now",now).param("normalized",normalize(p.proposedText())).param("proposalOrder",order++).param("metadata",json(Map.of())).update();for(var f:result.findings())jdbc.sql("INSERT INTO ai_editorial_finding(id,generation_job_id,operation_type,target_fact_id,target_fact_version_id,finding_type,severity,title,message,affected_text,source_evidence,confidence,suggested_action,finding_metadata,status,created_at) SELECT :id,:job,j.operation_type,:target,t.target_fact_version_id,:type,:severity,:title,:message,:affected,CAST(:evidence AS jsonb),:confidence,:action,CAST(:metadata AS jsonb),'OPEN',:now FROM ai_generation_job j JOIN ai_editorial_target t ON t.generation_job_id=j.id WHERE j.id=:job ON CONFLICT DO NOTHING").param("id",UUID.randomUUID()).param("job",job).param("target",f.targetFactId()).param("type",f.type()).param("severity",f.severity()).param("title",f.title()).param("message",f.message()).param("affected",blank(f.affectedPhrase()),Types.VARCHAR).param("evidence",json(f.evidence())).param("confidence",f.confidence(),Types.VARCHAR).param("action",blank(f.suggestedAction()),Types.VARCHAR).param("metadata",json(f.details()==null?Map.of():f.details())).param("now",now).update();var usage=result.usage();Integer input=usage==null?null:usage.inputTokens(),output=usage==null?null:usage.outputTokens();String resultType=result.revisions().isEmpty()&&result.findings().stream().anyMatch(f->"ALREADY_CLEAR".equals(f.type()))?"ALREADY_CLEAR":!result.revisions().isEmpty()?"PROPOSALS_AVAILABLE":"FINDINGS_AVAILABLE";jdbc.sql("UPDATE ai_generation_job SET status='COMPLETED',result_type=:resultType,completed_at=:now,input_tokens=:input,output_tokens=:output,total_tokens=:total,provider_request_id=:request,version=version+1 WHERE id=:id").param("resultType",resultType).param("now",now).param("input",input,Types.INTEGER).param("output",output,Types.INTEGER).param("total",input==null||output==null?null:input+output,Types.INTEGER).param("request",usage==null?null:usage.requestId(),Types.VARCHAR).param("id",job).update();}
  private void fail(UUID id,int retries,AiProviderException failure){if(failure.transientFailure()&&retries<maxRetries)jdbc.sql("UPDATE ai_generation_job SET status='QUEUED',retry_count=retry_count+1,next_attempt_at=:next,error_code=:code,error_message=:message,version=version+1 WHERE id=:id").param("next",now().plusSeconds(1L<<(retries+1))).param("code",failure.code()).param("message",failure.getMessage()).param("id",id).update();else jdbc.sql("UPDATE ai_generation_job SET status='FAILED',failed_at=:now,error_code=:code,error_message=:message,version=version+1 WHERE id=:id").param("now",now()).param("code",failure.code()).param("message",failure.getMessage()).param("id",id).update();}
  private boolean genericRationale(String value){if(value==null||value.isBlank())return true;String normalized=normalize(value);return Set.of("clarity rewrite","language simplification","rewrite","simplified").contains(normalized)||normalized.length()<20;}
  private void metric(Map<String,Object> row,String name){metric(name,String.valueOf(row.get("operation_type")),String.valueOf(row.get("prompt_version")));}
  private void metric(AiEditorialProviderClient.Request request,String name){metric(name,request.operation().name(),prompts.version(request.operation()));}
  private void metric(String name,String operation,String prompt){jdbc.sql("INSERT INTO ai_editorial_validation_metric(metric_name,operation_type,prompt_version,metric_count,updated_at) VALUES(:name,:operation,:prompt,1,:now) ON CONFLICT(metric_name,operation_type,prompt_version) DO UPDATE SET metric_count=ai_editorial_validation_metric.metric_count+1,updated_at=excluded.updated_at").param("name",name).param("operation",operation).param("prompt",prompt).param("now",now()).update();}
  private void parse(Map<String,Object> row,String key){try{row.put(key,mapper.readValue((String)row.get(key),Object.class));}catch(Exception e){throw new IllegalStateException(e);}}private String json(Object value){try{return mapper.writeValueAsString(value);}catch(Exception e){throw new IllegalStateException(e);}}private String blank(String value){return value==null||value.isBlank()?null:value.trim();}private String normalize(String value){return EditorialGrounding.normalizeMeaning(value);}private OffsetDateTime now(){return OffsetDateTime.now(ZoneOffset.UTC);}private AiApiException error(HttpStatus status,String code,String message){return new AiApiException(status,code,message);}
}
